export type Budget = {
    id: string;
    name: string;
    budget_name?: string;
    last_modified_on?: string;
    first_month?: string;
    last_month?: string;
    date_format?: DateFormat;
    currency_format?: CurrencyFormat;
    accounts: Account[];
    payees: Payee[];
    payee_locations: PayeeLocation[];
    category_groups: CategoryGroup[];
    categories: Category[];
    months: MonthDetail[];
    transactions: Transaction[];
    subtransactions: Subtransaction[];
    scheduled_transactions: ScheduledTransaction[];
    scheduled_subtransactions: ScheduledSubtransaction[];
};
export type DateFormat = 'YYYY/MM/DD' | 'YYYY-MM-DD' | 'DD-MM-YYYY' | 'DD/MM/YYYY' | 'DD.MM.YYYY' | 'MM/DD/YYYY' | 'YYYY.MM.DD' | null;
export type CurrencyFormat = {
    iso_code: string;
    example_format: string;
    decimal_digits: number;
    decimal_separator: string;
    symbol_first: boolean;
    group_separator: string;
    currency_symbol: string;
    display_symbol: boolean;
} | null;
export type Account = {
    id: string;
    name: string;
    type: AccountType;
    on_budget: boolean;
    closed: boolean;
    note?: string | null;
    balance: number;
    cleared_balance: number;
    uncleared_balance: number;
    transfer_payee_id: string | null;
    direct_import_linked?: boolean;
    direct_import_in_error?: boolean;
    last_reconciled_at?: string | null;
    debt_original_balance?: number | null;
    debt_interest_rates?: LoanAccountPeriodicValue | null;
    debt_minimum_payments?: LoanAccountPeriodicValue | null;
    debt_escrow_amounts?: LoanAccountPeriodicValue | null;
    deleted: boolean;
};
export type LoanAccountPeriodicValue = Record<string, number> | null;
export type AccountType = 'checking' | 'savings' | 'cash' | 'creditCard' | 'lineOfCredit' | 'otherAsset' | 'otherLiability' | 'mortgage' | 'autoLoan' | 'studentLoan' | 'personalLoan' | 'medicalDebt' | 'otherDebt';
export type Payee = {
    id: string;
    name: string;
    transfer_account_id?: string | null;
    deleted: boolean;
    transfer_acct?: string;
};
export type PayeeLocation = {
    id: string;
    payee_id: string;
    latitude: string;
    longitude: string;
    deleted: boolean;
};
export type CategoryGroup = {
    id: string;
    name: string;
    deleted: boolean;
    hidden: boolean;
    note?: string;
};
export type Category = {
    id: string;
    category_group_id: string;
    category_group_name?: string;
    name: string;
    deleted: boolean;
    hidden: boolean;
    original_category_group_id?: string | null;
    note?: string;
    budgeted: number;
    activity: number;
    balance: number;
    goal_type?: GoalType | null;
    goal_needs_whole_amount?: boolean | null;
    goal_day?: number | null;
    goal_cadence?: number | null;
    goal_cadence_frequency?: number | null;
    goal_creation_month?: string | null;
    goal_target?: number | null;
    goal_target_month?: string | null;
    goal_percentage_complete?: number | null;
    goal_months_to_budget?: number | null;
    goal_under_funded?: number | null;
    goal_overall_funded?: number | null;
    goal_overall_left?: number | null;
    goal_snoozed_at?: string | null;
};
export type GoalType = 'TB' | 'TBD' | 'MF' | 'NEED' | 'DEBT';
export type Transaction = {
    id: string;
    date: string;
    amount: number;
    memo?: string | null;
    cleared: TransactionClearedStatus;
    approved: boolean;
    flag_color?: TransactionFlagColor | null;
    flag_name?: TransactionFlagName | null;
    account_id: string;
    payee_id?: string | null;
    category_id?: string | null;
    transfer_account_id?: string | null;
    transfer_transaction_id?: string | null;
    matched_transaction_id?: string | null;
    import_id?: string | null;
    import_payee_name?: string | null;
    import_payee_name_original?: string | null;
    debt_transaction_type?: DebtTransactionType | null;
    deleted: boolean;
};
export type TransactionClearedStatus = 'cleared' | 'uncleared' | 'reconciled';
export type TransactionFlagColor = 'red' | 'orange' | 'yellow' | 'green' | 'blue' | 'purple' | '' | null;
export type TransactionFlagName = string | null;
export type DebtTransactionType = 'payment' | 'refund' | 'fee' | 'interest' | 'escrow' | 'balanceAdjustment' | 'credit' | 'charge';
export type Subtransaction = {
    id: string;
    transaction_id: string;
    amount: number;
    memo?: string | null;
    payee_id?: string | null;
    payee_name?: string | null;
    category_id?: string | null;
    category_name?: string | null;
    transfer_account_id?: string | null;
    transfer_transaction_id?: string | null;
    deleted: boolean;
};
export type ScheduledTransaction = {
    id: string;
    date_first: string;
    date_next: string;
    frequency: ScheduledTransactionFrequency;
    amount: number;
    memo?: string | null;
    flag_color?: TransactionFlagColor | null;
    flag_name?: TransactionFlagName | null;
    account_id: string;
    payee_id?: string | null;
    category_id?: string | null;
    transfer_account_id?: string | null;
    deleted: boolean;
};
export type ScheduledSubtransaction = {
    id: string;
    scheduled_transaction_id: string;
    amount: number;
    memo?: string | null;
    payee_id?: string | null;
    payee_name?: string | null;
    category_id?: string | null;
    category_name?: string | null;
    transfer_account_id?: string | null;
    deleted: boolean;
};
export type ScheduledTransactionFrequency = 'never' | 'daily' | 'weekly' | 'everyOtherWeek' | 'twiceAMonth' | 'every4Weeks' | 'monthly' | 'everyOtherMonth' | 'every3Months' | 'every4Months' | 'twiceAYear' | 'yearly' | 'everyOtherYear';
export type MonthSummary = {
    month: string;
    note?: string | null;
    income: number;
    budgeted: number;
    activity: number;
    to_be_budgeted: number;
    age_of_money?: number | null;
    deleted: boolean;
};
export type MonthDetail = MonthSummary & {
    categories: Category[];
};
